import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"54. Superannuation","description":"","frontmatter":{"title":"54. Superannuation","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["wages","superannuation"]},"headers":[],"relativePath":"ebas/mspp/classification-salaries/54-superannuation.md","filePath":"ebas/mspp/classification-salaries/54-superannuation.md"}'),i={name:"ebas/mspp/classification-salaries/54-superannuation.md"};function r(s,e,p,l,u,c){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_54-superannuation" tabindex="-1">54. Superannuation <a class="header-anchor" href="#_54-superannuation" aria-label="Permalink to &quot;54. Superannuation&quot;">​</a></h1><p><strong>54.1</strong> Superannuation Legislation</p><p><strong>a.</strong> The subject of superannuation is dealt with extensively by federal legislation including the Superannuation Guarantee (Administration) Act 1992, the Superannuation Guarantee Charge Act 1992, the Superannuation Industry (Supervision) Act 1993 and the Superannuation (Resolution of Complaints) Act 1993. This legislation, as varied from time to time, governs the superannuation rights and obligations of the parties.</p><p><strong>b.</strong> This clause is ancillary to and supplements the legislative provisions.</p><p><strong>c.</strong> Employer superannuation contributions on behalf of new Employees will be made to the Employee’s choice of Fund from the following:</p><p><strong>(i)</strong> HESTA (or successor);</p><p><strong>(ii)</strong> The Employee’s preferred fund.</p><p><strong>d.</strong> Superannuation contributions will be paid by the Employer into the Employee’s preferred Fund. Superannuation contributions will be paid on ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth).</p><p><strong>e.</strong> An Employee may sacrifice part of their salary as an Employer contribution to superannuation.</p><p><strong>f.</strong> Where an Employee sacrifices part of their salary pursuant to clause 54.1e the Superannuation Guarantee Charge (SGC) contribution by the Employer will be calculated on the Employee’s pre-salary sacrifice rate of pay.</p><p><strong>g.</strong> Where pursuant to <a href="/eba/ebas/mspp/classification-salaries/51-salaries-and-allowances.html">clause 51.5</a> (Salary Packaging) of this Agreement, an Employee packages part of their salary, the Employee’s SGC contribution shall be calculated on the pre-packaged rate of pay.</p><p><strong>54.2</strong> Fund</p><p><strong>a.</strong> Fund for the purpose of this clause shall mean:</p><p><strong>(i)</strong> HESTA, as may be amended from time to time, and includes any superannuation scheme which may be made in succession thereto; or</p><p><strong>(ii)</strong> the requirements of the Superannuation Guarantee (Administration) Act 1992.</p><p><strong>b.</strong> Each new Employee shall be required to complete a membership application on commencement of employment and the Employer shall forward the completed application to the Fund within 4 weeks of the or commencement of employment.</p><p><strong>c.</strong> Where an Employee fails to elect a superannuation fund within 4 weeks of commencing employment the default Fund will be HESTA. Provided that where an Employee is already a member of another Fund, from 1 November 2021 the default Fund will be the stapled default Fund as set out in the Superannuation Guarantee (Administration) Act 1992 as amended.</p><p><strong>d.</strong> Each Employee shall be eligible to receive contributions from the date of commencing employment, notwithstanding the date the membership application prescribed in clause 54.2b was forwarded to the Fund.</p><p><strong>54.3</strong> Employer Contributions On Behalf Of Each Employee</p><p><strong>a.</strong> The Employer shall contribute to the Fund such contributions as required to comply with the Superannuation Guarantee (Administration) Act 1992 and Superannuation Guarantee Charge Act 1992 as amended from time to time.</p><p><strong>b.</strong> The amount of contributions to the Fund shall be calculated to the nearest ten cents, any fraction below five cents shall be disregarded.</p><p><strong>c.</strong> Such contributions shall be made monthly by the last day of the month following, the total of the weekly contribution amounts accruing in the previous month in respect of each Employee.</p><p><strong>d.</strong> The Fund and the amount of contributions paid in accordance with this clause and clause 54.1e shall be included in pay advice notices provided by the Employer to each Employee.</p><p><strong>e.</strong> Contributions shall continue to be paid in accordance with this clause during any period in respect of which any Employee is entitled to receive accident pay in accordance with <a href="/eba/ebas/mspp/accident-pay-allowances/90-accident-pay.html">clause 90</a> (Accident Pay).</p><p><strong>f.</strong> Contributions shall continue to be paid during any period in respect of which an Employee in on paid Sabbatical Leave under <a href="/eba/ebas/mspp/leave/76-sabbatical-leave.html">clause 76</a>.</p><p><strong>g.</strong> The Employer will also make a superannuation contribution for any period of paid parental leave under <a href="/eba/ebas/mspp/leave/69-breast-feeding-facilities.html">clause 69</a>, Parental Leave until 20 December 2021, after which superannuation shall be paid on parental leave (paid and unpaid) as outlined below.</p><p><strong>54.4</strong> Superannuation during parental leave – from 21 December 2021 From 21 December 2021, the Employer will make superannuation contributions throughout any period of parental leave, paid or unpaid. Such contributions will be calculated as follows:</p><p><strong>a.</strong> The Employee&#39;s ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre- salary packaging earnings and any additional amounts consistent with the trust deed of the superannuation fund over 26 full pay periods immediately prior to commencing parental leave and divided by 52 (Weekly Parental Leave Super Contribution).</p><p><strong>b.</strong> The Weekly Parental Leave Super Contribution will be paid during each week of Parental Leave (both paid and unpaid) save that:</p><p><strong>(i)</strong> The Employee will receive a pro rata payment for any period of less than 1 week; and</p><p><strong>(ii)</strong> Where, during the period of parental leave (either paid or unpaid), the Employee&#39;s rate of pay increases, the Employee&#39;s Weekly Parental Leave Super Contribution will be adjusted accordingly from the operative date of the pay increase.</p><p><strong>54.5</strong> Employee After Tax Contributions</p><p><strong>a.</strong> An Employee may make after tax contributions to the Fund in addition to the contributions made by the Employer.</p><p><strong>b.</strong> An Employee who wishes to make after tax contributions must authorise the Employer in writing to pay into the Fund, from the Employee’s wages, amounts specified by the Employee.</p><p><strong>c.</strong> An Employer who receives written authorisation from an Employee must commence making payments into the Fund on behalf of the Employee within fourteen days of receiving the authorisation.</p><p><strong>d.</strong> An Employee may vary their after tax contributions by a written authorisation and the Employer must vary the after tax contributions within fourteen days of receiving the authorisation. An Employee may only vary their after tax contributions once in any month.</p><p><strong>e.</strong> Employee after tax contributions to the Fund requested under this clause shall be expressed in whole dollars.</p><p>OVERTIME, SHIFTWORK AND WEEKEND WORK</p><p>Plain language terms: super, SG, retirement fund.</p>',39)])])}const m=t(i,[["render",r]]);export{d as __pageData,m as default};
